import { charsFontWidth12pixelsSize400Map } from '../../text-ellipsis/chars-font-width-map.js';
import { calculateWidth } from '../../text-ellipsis/truncate-string.js';
import {
  DEFAULT_SERIES_NAME_LINES,
  MIN_TOOLTIP_WIDTH,
  SYMBOL_AND_SPACING_WIDTH,
  TOOLTIP_WRAPPER_PADDING,
} from '../constants.js';

/**
 * Estimates the size (height) of a series item for virtualization
 * @param item - The series item data
 * @param maxContainerWidth - Maximum container width available
 * @returns Estimated height in pixels
 */
export const estimateSeriesItemSize = (
  item: Record<string, unknown>,
  maxContainerWidth: number,
): number => {
  const baseHeight = 24;

  const multiLine = ('multiLine' in item ? item.multiLine : false) as boolean;
  const maxLines = (
    'maxLines' in item ? item.maxLines : DEFAULT_SERIES_NAME_LINES
  ) as number;

  const containerWidth =
    Math.max(maxContainerWidth, MIN_TOOLTIP_WIDTH) -
    (SYMBOL_AND_SPACING_WIDTH + TOOLTIP_WRAPPER_PADDING);

  let lineCount = 1;

  if (Array.isArray(item.name)) {
    lineCount = item.name.length;
  } else if (typeof item.name === 'string' && multiLine) {
    const textWidth = calculateWidth(
      item.name,
      charsFontWidth12pixelsSize400Map,
    );

    if (textWidth > containerWidth) {
      lineCount = Math.min(Math.ceil(textWidth / containerWidth), maxLines);
    }
  }

  let descriptionLineCount = 0;
  const description = ('description' in item ? item.description : undefined) as
    | string
    | undefined;
  if (typeof description === 'string' && description.length > 0) {
    descriptionLineCount = 1;
    if (multiLine) {
      const descriptionWidth = calculateWidth(
        description,
        charsFontWidth12pixelsSize400Map,
      );
      if (descriptionWidth > containerWidth) {
        descriptionLineCount = Math.min(
          Math.ceil(descriptionWidth / containerWidth),
          maxLines,
        );
      }
    }
  }

  return baseHeight + (lineCount + descriptionLineCount - 1) * 16;
};
